INSERT INTO "public"."medical_condition" ("id", "condition_code", "condition_name", "description") VALUES (1, 'MNT-001', 'Schizophrenia', 'severe mental disorder affecting how a person thinks, feels, and behaves, often causing a disconnection from reality. Symptoms include hallucinations, delusions, and disorganized speech.'), (2, 'DGS-001', 'Diarrhea', 'loose, watery stools, usually caused by viral gastroenteritis, bacteria, or parasites.'), (3, 'RSP-001', 'Asthma', 'a chronic, often lifelong, respiratory condition characterized by airway inflammation, narrowing, and mucus production, causing wheezing, shortness of breath, chest tightness, and coughing.'), (4, 'MNT-002', 'Depression', 'persistent feeling of sadness and loss of interest affecting daily functioning'), (5, 'MNT-003', 'Anxiety Disorder', 'excessive fear or worry that interferes with daily activities'), (6, 'DGS-002', 'Gastritis', 'inflammation of the stomach lining causing pain and nausea'), (7, 'DGS-003', 'Constipation', 'infrequent or difficult bowel movements often causing discomfort'), (8, 'RSP-002', 'Asthma', 'chronic condition causing airway inflammation and breathing difficulty'), (9, 'RSP-003', 'Bronchitis', 'inflammation of the bronchial tubes leading to cough and mucus production'), (10, 'CRD-001', 'Hypertension', 'high blood pressure increasing risk of heart disease and stroke'), (11, 'CRD-002', 'Coronary Artery Disease', 'narrowing of heart arteries reducing blood flow to the heart'), (12, 'NRL-001', 'Epilepsy', 'neurological disorder marked by recurrent seizures'), (13, 'NRL-002', 'Migraine', 'severe recurring headaches often accompanied by nausea and sensitivity to light'), (14, 'SKN-001', 'Eczema', 'skin condition causing itchy and inflamed patches'), (15, 'SKN-002', 'Acne', 'common skin condition involving clogged pores and pimples'), (16, 'END-001', 'Diabetes', 'metabolic disorder characterized by high blood sugar levels'), (17, 'END-002', 'Hypothyroidism', 'underactive thyroid gland leading to fatigue and weight gain'), (18, 'MUS-001', 'Arthritis', 'inflammation of joints causing pain and stiffness'), (19, 'MUS-002', 'Osteoporosis', 'weakening of bones increasing fracture risk'), (20, 'INF-001', 'Influenza', 'viral infection causing fever, aches, and respiratory symptoms'), (21, 'INF-002', 'Tuberculosis', 'bacterial infection affecting the lungs and spreading through air'), (22, 'MNT-004', 'Bipolar Disorder', 'mental condition with extreme mood swings between highs and lows'), (23, 'DGS-004', 'Peptic Ulcer', 'sores in the stomach lining causing burning pain');
